module RefModule(
    A,
    B,
    C
);input [3:0] A;
    input [3:0] B;
    output [4:0] C;

    wire [3:0] obf_sum;
    wire overflow;

    assign obf_sum = A + B;

    assign overflow = ((A[3] & B[3]) | (A[3] & ~obf_sum[3]) | (B[3] & ~obf_sum[3]));

    assign C = {overflow, obf_sum};

endmodule
